/**
 * Valid ?tab= values per route, used only for a dev-time warning.
 * Mirrors VALID_TABS in settings/page.jsx and the tab list in billing/leads.
 */
const VALID_TABS_BY_ROUTE = {
  "/settings": [
    "general",
    "user-data",
    "chat-modes",
    "localization",
    "personas",
    "instructions",
  ],
  "/billing": ["addons"],
  "/leads": ["human-settings"],
};

/** Resolve an index entry into a routable href. */
export function buildHref(entry) {
  let href = entry.url;
  if (entry.tab) href += `?tab=${encodeURIComponent(entry.tab)}`;
  if (entry.hash) href += `#${entry.hash}`;
  return href;
}

// Dev-only sanity check: a typo'd tab silently falls back to the default tab
// with no error at runtime, which is painful to notice. Warn loudly instead.
if (process.env.NODE_ENV === "development") {
  for (const entry of searchIndex) {
    if (!entry.tab) continue;
    const valid = VALID_TABS_BY_ROUTE[entry.url];
    if (valid && !valid.includes(entry.tab)) {
      console.warn(
        `[search-index] Entry "${entry.id}" has tab "${entry.tab}" which is not valid for ${entry.url}. Expected one of: ${valid.join(", ")}`,
      );
    }
  }
}
